import{_ as e,c as t,o as a,N as r}from"./chunks/framework.0799945b.js";const b=JSON.parse('{"title":"What is ForNet","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-fornet.md","lastUpdated":1683817037000}'),o={name:"guide/what-is-fornet.md"},i=r('<h1 id="what-is-fornet" tabindex="-1">What is ForNet <a class="header-anchor" href="#what-is-fornet" aria-label="Permalink to &quot;What is ForNet&quot;">​</a></h1><p>ForNet used to create virtual local network across the Internet. It&#39;s based on <a href="https://github.com/cloudflare/boringtun" target="_blank" rel="noreferrer">BoringTun</a>, WireGuard implementation written by Rust. It now provider Linux and macOS client, and Windows、Android would come soon.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>ForNet is now in <code>BETA</code> status, we will do our best to fix bugs to make it stable.</p><p>Just want to try it out? Skip to the <a href="./quick-start">Quick Start</a>.</p></div><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><ul><li><strong>Home Lab</strong> [WIP]Easy try, Device can access each other by P2P or Relay, and you can configure all your device in one web page.</li><li><strong>Enterprise Secure Network</strong> ForNet integrated with Keycloak, IT would easily manage the employee permissions to access company private network.</li></ul><h2 id="what-about-wireguard" tabindex="-1">What about WireGuard? <a class="header-anchor" href="#what-about-wireguard" aria-label="Permalink to &quot;What about WireGuard?&quot;">​</a></h2><p>ForNet is based on <a href="https://github.com/cloudflare/boringtun" target="_blank" rel="noreferrer">BoringTun</a> which is the Rust implementation of WireGuard. We very appreciate their efforts to create such brilliant project. In future develop plan, we would support WireGuard original client.</p>',7),s=[i];function n(c,l,u,d,h,p){return a(),t("div",null,s)}const f=e(o,[["render",n]]);export{b as __pageData,f as default};
